code = """import json

# Load the data
reviews_data = locals()['var_functions.query_db:12']
la_businesses_data = locals()['var_functions.query_db:30']

# Create dictionary for business names
business_names = {}
for biz in la_businesses_data:
    business_names[biz['gmap_id']] = biz['name']

# Calculate average ratings
ratings_by_business = {}
for review in reviews_data:
    gmap_id = review['gmap_id']
    if gmap_id in business_names:
        if gmap_id not in ratings_by_business:
            ratings_by_business[gmap_id] = []
        ratings_by_business[gmap_id].append(int(review['rating']))

# Calculate averages
results = []
for gmap_id, ratings in ratings_by_business.items():
    if ratings:
        avg_rating = sum(ratings) / len(ratings)
        results.append({
            'name': business_names[gmap_id],
            'average_rating': round(avg_rating, 2),
            'review_count': len(ratings)
        })

# Sort by rating desc
results_sorted = sorted(results, key=lambda x: x['average_rating'], reverse=True)

# Take top 5
top_5 = results_sorted[:5]

# Create output string
output = "Top 5 Businesses in Los Angeles, California by Average Rating:\n\n"
for i, biz in enumerate(top_5, 1):
    output += f"{i}. {biz['name']}\n"
    output += f"   Average Rating: {biz['average_rating']}/5.0\n"
    output += f"   Number of Reviews: {biz['review_count']}\n\n"

print('__RESULT__:')
print(output)"""

